// Parse the synthesis output and prepare data for document generation
const input = $input.first().json;

// Get the synthesis raw output
const synthesisRaw = input.synthesis_raw || $node['23_Synthesis'].json?.output;

// Extract text from the synthesis output
let synthesisText = '';
if (Array.isArray(synthesisRaw)) {
  // Handle array format: output[0].content[0].text
  synthesisText = synthesisRaw[0]?.content?.[0]?.text || '';
} else if (typeof synthesisRaw === 'string') {
  synthesisText = synthesisRaw;
} else if (synthesisRaw?.message?.content) {
  synthesisText = typeof synthesisRaw.message.content === 'string' 
    ? synthesisRaw.message.content 
    : synthesisRaw.message.content[0]?.text || '';
}

// Parse the JSON from the synthesis text (remove markdown code fences if present)
let synthesisParsed = {};
try {
  // Remove markdown code fences if present
  let jsonStr = synthesisText.trim();
  if (jsonStr.startsWith('```json')) {
    jsonStr = jsonStr.slice(7); // Remove ```json
  } else if (jsonStr.startsWith('```')) {
    jsonStr = jsonStr.slice(3); // Remove ```
  }
  if (jsonStr.endsWith('```')) {
    jsonStr = jsonStr.slice(0, -3); // Remove trailing ```
  }
  jsonStr = jsonStr.trim();

  if (jsonStr) {
    synthesisParsed = JSON.parse(jsonStr);
  }
} catch (e) {
  // If parsing fails, keep the raw text available
  synthesisParsed = { raw_text: synthesisText, parse_error: e.message };
}

// Stringify the synthesis for use in prompts (prevents [object Object])
const synthesisForPrompts = JSON.stringify(synthesisParsed, null, 2);

// Pass through all the data needed for document generation
return [{
  json: {
    synthesis_raw: synthesisRaw,
    synthesis_parsed: synthesisParsed,
    synthesis_text: synthesisForPrompts, // Use this in prompts!
    session_id: input.session_id,
    email: input.email,
