// Helper to safely get node data
function safeGet(nodeName, limit = 8000) {
  try {
    const node = $node[nodeName];
    if (!node || !node.json) return null;
    const s = JSON.stringify(node.json);
    return s.length > limit ? JSON.parse(s.slice(0, limit)) : node.json;
  } catch (e) {
    return null;
  }
}

// Collect all research data organized by category
const research = {
  // Core market research (existing)
  market: safeGet('17a_Tavily_Market'),
  competitors: safeGet('17b_Tavily_Competitors'),
  customer: safeGet('17c_Tavily_Customer'),
  business_model: safeGet('17d_Tavily_Business'),
  trends: safeGet('17e_Tavily_Trends'),

  // New research streams
  why_now: safeGet('17f_Tavily_WhyNow'),
  proof_signals: safeGet('17g_Tavily_ProofSignals'),
  keywords_seo: safeGet('17h_Tavily_Keywords'),

  // Community signals
  google_trends: safeGet('19_Trends'),
  hackernews: safeGet('20_HackerNews'),
  reddit: safeGet('Get dataset items')
};

// Extract proof signals summary
const proofSignals = {
  reddit_discussions: research.reddit ? (research.reddit.items || []).slice(0, 10) : [],
  hackernews_stories: research.hackernews ? (research.hackernews.hits || []).slice(0, 10) : [],
  google_trends_data: research.google_trends,
  tavily_proof: research.proof_signals
};

// Extract why now factors
const whyNowFactors = {
  recent_news: research.why_now,
  trend_data: research.google_trends,
  market_shifts: research.trends
};

// Extract keyword opportunities
const keywordData = {
  primary_keywords: input.queries.keyword_queries || [],
  seo_research: research.keywords_seo,
  trend_terms: input.queries.google_trends_terms || []
};

return [{
  json: {
    research: research,
    proof_signals: proofSignals,
    why_now_factors: whyNowFactors,
    keyword_data: keywordData,
    session_id: input.session_id,
