    assumption_score: totalWeight > 0 ? Math.round(((totalWeight - collectedWeight) / totalWeight) * 100) : 100
  };
}

const metrics = calculateMetrics(state.data_points);

let phase = 'discovery';
if (state.current_turn > 20 && state.current_turn <= 40) phase = 'deepening';
if (state.current_turn > 40 && state.current_turn <= 55) phase = 'business';
if (state.current_turn > 55) phase = 'wrapping';

const criticalsCovered = state.guardrails.critical_topics.every(
  topic => state.data_points[topic]?.source === 'collected'
);

const canEnd = (
  state.current_turn >= state.guardrails.min_turns &&
  metrics.confidence_score >= state.guardrails.min_confidence &&
