for (const [_, point] of Object.entries(state.data_points)) {
  totalWeight += point.weight;
  if (point.source === 'collected') collectedWeight += point.weight;
}
const finalMetrics = { confidence_score: Math.round((collectedWeight / totalWeight) * 100) };

const endMessage = `Great! I've gathered everything I need for your **${summary.idea_summary}** business plan.\n\n📊 **Confidence: ${finalMetrics.confidence_score}%**\n\nGenerating your business plan now. You'll receive an email shortly with:\n- Business Plan\n- Positioning Strategy\n- Competitive Analysis\n\nThank you! 🚀`;

return [{
  json: {
    state: state,
    summary: summary,
    collected_data: collected,
    interview_qa: interviewQA,
    final_metrics: finalMetrics,
    response: {
      action: 'complete',
      session_id: state.session_id,
      message: endMessage,
      turn: state.current_turn,
      metrics: finalMetrics,
      interview_complete: true
    }
  }
}];

