const items = $input.all();

function extractText(item, fallback) {
  if (!item?.json) return fallback;
  const json = item.json;

  // OpenAI Responses API format - output[0].content[0].text
  if (Array.isArray(json.output) && json.output[0]?.content?.[0]?.text) {
    return json.output[0].content[0].text;
  }
  // OpenAI langchain node v2.1 - message.content is a string
  if (typeof json.message?.content === 'string') {
    return json.message.content;
  }
  // Array format (older versions) - message.content[0].text
  if (Array.isArray(json.message?.content) && json.message.content[0]?.text) {
    return json.message.content[0].text;
  }
  // Direct output field (string)
  if (typeof json.output === 'string') return json.output;
  if (typeof json.text === 'string') return json.text;

  return fallback;
}

// Items are in order of Merge inputs (0-7)
const documents = {
  business_plan: extractText(items[0], 'Business plan generation failed'),
  positioning: extractText(items[1], 'Positioning strategy generation failed'),
  competitive_analysis: extractText(items[2], 'Competitive analysis generation failed'),
  why_now: extractText(items[3], 'Why Now analysis generation failed'),
  proof_signals: extractText(items[4], 'Proof Signals generation failed'),
  keywords_seo: extractText(items[5], 'Keywords & SEO generation failed'),
  customer_profile: extractText(items[6], 'Customer Profile generation failed'),
  value_equation: extractText(items[7], 'Value Equation generation failed')
};

return [{
  json: {
    ...documents,
    document_count: Object.keys(documents).length,
    generated_at: new Date().toISOString()
  }
}];
